#include <bits/stdc++.h>
using namespace std;

int C(int x,int y){
    if(x<y || x<0 || y<0)
        return 0;
    int res=1;
    for(int i=x;i>x-y;i--)
        res*=i;
    for(int i=1;i<=y;i++)
        res/=i;
    return res;
}

int main(){
    int n,r;
    scanf("%d%d",&n,&r);
    long long ans=0;
    for(int i=0;i<r;i++)
        ans+=(i%2?-1ll:1ll)*C(r,i)*pow(r-i,n);
    printf("%lld",ans);
    return 0;
}
